(window.webpackJsonp=window.webpackJsonp||[]).push([[273],{900:function(n,i){n.exports="\x3c!-- \ntitle: 12-CSS操作\nsort: \n--\x3e \n# CSS进阶\n\n## 定位`position`\n\n### static\n\n> 固定位置，不随窗口而移动\n>\n> 默认position\n\n```css\ndiv {\n    position: static;\n    border: 3px solid #73AD21;\n}\n```\n\n### fixed\n\n> 相对浏览器窗口为固定位置\n\n```css\np\n{\n\tposition:fixed;\n\ttop:30px;\n\tright:5px;\n}\n```\n\n### relative\n\n> 相对正常位置的移动\n>\n> ![image-20200726100439709](https://gitee.com/nmdfzf404/Image-hosting/raw/master/20200726100446.png)\n\n```css\nh2\n{\n    position:relative;\n    left:-20px;\n}\nh2\n{\n    position:relative;\n    left:20px;\n}\n```\n\n### absolute\n\n> 相对于已定位的父元素，假如没有，则相对于html\n>\n> `position:absolute;`\n\n### sticky\n\n> 粘贴定位，元素不会出页面。\n>\n> `position: sticky;`\n\n## Overflow\n\n> 页面内滚动条\n>\n> | 值      | 描述                                                     |\n> | :------ | :------------------------------------------------------- |\n> | visible | 默认值。内容不会被修剪，会呈现在元素框之外。             |\n> | hidden  | 内容会被修剪，并且其余内容是不可见的。                   |\n> | scroll  | 内容会被修剪，但是浏览器会显示滚动条以便查看其余的内容。 |\n> | auto    | 如果内容被修剪，则浏览器会显示滚动条以便查看其余的内容。 |\n> | inherit | 规定应该从父元素继承 overflow 属性的值。                 |\n\n```css\ndiv {\n    width: 200px;\n    height: 50px;\n    background-color: #eee;\n    overflow: auto;\n}\n```\n\n## 浮动\n\n> 在元素的水平方向浮动，不能上下\n>\n> `float:right;`\n>\n> 清除： `clear:both`\n\n## 布局\n\n### 对齐\n\n> 元素居中：`margin: auto;`\n>\n> 文本居中：`text-align: center;`\n>\n> 定位对齐：`position: absolute; right: 0px;`\n>\n> 将div使用overflow，使元素包括\n>\n> 垂直居中：`padding: 70px 0; text-align: center`\n\n## 选择\n\n> `div p{}`：选择div中所有p元素\n>\n> `div>p`：直接p元素\n>\n> `div+p`：div后的第一个p元素\n>\n> `div~p`：div后的所有p元素\n\n## 伪类\n\n```css\na:link {color:#FF0000;} /* 未访问的链接 */\na:visited {color:#00FF00;} /* 已访问的链接 */\na:hover {color:#FF00FF;} /* 鼠标划过链接 */\na:active {color:#0000FF;} /* 已选中的链接 */\n\na.red:visited {color:#FF0000;}\t/* 与class配合使用 */\n/* 匹配第一个子元素 */\np:first-child {}\n/* 匹配所有p中第一个<i>元素 */\np > i:first-child\n/* 匹配第一个p中所有<i>元素 */\np:first-child i\n```\n\n### 伪元素\n\n> `p:first-line`：p的第一行\n>\n> `h1:before `：h1之前\n>\n> `h1:after`：h1之后"}}]);